# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

// Define the base directory for templates
define('TEMPLATE_DIR', __DIR__ . '/templates/');

// Define allowed pages (whitelist for security)
$allowed_pages = [
    'home',
    'about',
    'contact',
    'services',
    'blog',
    'portfolio',
    'faq',
    'privacy',
    'terms',
    '404'
];

// Get the requested page from URL parameter, default to 'home'
$page = isset($_GET['page']) ? $_GET['page'] : 'home';

// Sanitize the page parameter
// Remove any directory traversal attempts
$page = basename($page);

// Remove any non-alphanumeric characters except hyphens and underscores
$page = preg_replace('/[^a-zA-Z0-9_-]/', '', $page);

// Convert to lowercase for consistency
$page = strtolower($page);

// Validate the page against the whitelist
if (!in_array($page, $allowed_pages)) {
    $page = '404';
}

// Build the full file path
$template_file = TEMPLATE_DIR . $page . '.php';

// Verify the file exists and is within the templates directory
$real_template_path = realpath($template_file);
$real_template_dir = realpath(TEMPLATE_DIR);

// Security check: ensure the resolved path is within the templates directory
if ($real_template_path === false || strpos($real_template_path, $real_template_dir) !== 0) {
    $template_file = TEMPLATE_DIR . '404.php';
    $page = '404';
}

// Set the current page variable for use in templates
$current_page = $page;

// Start output buffering
ob_start();

?>
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title><?php echo ucfirst(str_replace(['-', '_'], ' ', $current_page)); ?> - My CMS</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        header { background: #2c3e50; color: #fff; padding: 1rem 2rem; }
        header h1 { display: inline-block; }
        nav { margin-top: 0.5rem; }
        nav a { color: #ecf0f1; text-decoration: none; margin-right: 1rem; padding: 0.3rem 0.6rem; border-radius: 3px; }
        nav a:hover, nav a.active { background: #34495e; }
        main { max-width: 1200px; margin: 2rem auto; padding: 0 2rem; min-height: 60vh; }
        footer { background: #2c3e50; color: #ecf0f1; text-align: center; padding: 1rem; margin-top: 2rem; }
    </style>
</head>
<body>

<header>
    <h1>My CMS</h1>
    <nav>
        <?php
        $nav_pages = ['home', 'about', 'services', 'blog', 'portfolio', 'contact'];
        foreach ($nav_pages as $nav_page):
            $active_class = ($current_page === $nav_page) ? ' class="active"' : '';
        ?>
            <a href="?page=<?php echo $nav_page; ?>"<?php echo $active_class; ?>>
                <?php echo ucfirst($nav_page); ?>
            </a>
        <?php endforeach; ?>
    </nav>
</header>

<main>
    <?php
    // Include the template file
    if (file_exists($template_file)) {
        include $template_file;
    } else {
        // Fallback if even the 404 template doesn't exist
        http_response_code(404);
        echo '<h2>Page Not Found</h2>';
        echo '<p>Sorry, the page you are looking for does not exist.</p>';
        echo '<p><a href="?page=home">Return to Home</a></p>';
    }
    ?>
</main>

<footer>
    <p>&copy; <?php echo date('Y'); ?> My CMS. All rights reserved.</p>
</footer>

</body>
</html>
<?php

// Flush output buffer
ob_end_flush();

